UPDATE sequence_config
   SET max_id = #{newMaxId}
 WHERE seq_name = #{seqName}
   AND max_id = #{oldMaxId}

UPDATE sequence_record
   SET status = #{status}
 WHERE id = #{id}

mapper.delete:
DELETE FROM sequence_record
 WHERE alloc_time < #{beforeTime}
   AND status IN ('EXPIRED', 'RECYCLED')
